mapper.select:
SELECT DISTINCT e.user_id
FROM course_enrollment e
JOIN course c ON c.id = e.course_id AND c.is_deleted = 0
JOIN `user` u ON u.id = e.user_id AND u.is_deleted = 0
WHERE c.teacher_id = #{teacherId}
  AND e.is_deleted = 0

    AND (u.nickname LIKE CONCAT('%', #{nickname}, '%')
     OR  u.username LIKE CONCAT('%', #{nickname}, '%'))


    AND e.last_learn_time >= #{learnStart}


    AND e.last_learn_time <= #{learnEnd}
